// docs/lib.js
// Self-contained browser module generated by build-web.cjs.
// Identity from package.json; functions extracted from src/lib/main.js.
// Do not edit — regenerate with: npm run build:web
export const name = "repo";
export const version = "0.1.0";
export const description = "";

export function getIdentity() {
  return { name, version, description };
}

export function createState({ initialAltitude = 1000, initialVelocity = 40, initialFuel = 25 } = {}) {
  return Object.freeze({
    altitude: Number(initialAltitude),
    velocity: Number(initialVelocity),
    fuel: Number(initialFuel),
    tick: 0,
    landed: false,
    crashed: false,
  });
}

export function step(state, thrustUnits = 0) {
  // Do not mutate input state; return a new frozen state object
  const thrustRequested = Number(thrustUnits) || 0;
  const thrust = Math.max(0, Math.floor(thrustRequested));
  const burn = Math.min(thrust, state.fuel);

  const gravity = 2; // m/s per tick
  const thrustEffectPerUnit = 4; // m/s per fuel unit

  const newVelocity = state.velocity + gravity - thrustEffectPerUnit * burn;
  const newAltitude = state.altitude - newVelocity;

  let landed = false;
  let crashed = false;

  if (newAltitude <= 0) {
    // We have reached or passed the surface this tick
    if (newVelocity <= 4) landed = true;
    else crashed = true;
  }

  const result = {
    altitude: landed || crashed ? 0 : newAltitude,
    velocity: newVelocity,
    fuel: state.fuel - burn,
    tick: state.tick + 1,
    landed,
    crashed,
  };

  return Object.freeze(result);
}

export function simulate(initialState, controller) {
  const trace = [];
  // Accept a plain object - do not mutate it
  let state = Object.freeze({ ...initialState });
  trace.push(state);

  const maxTicks = 10000;
  while (!state.landed && !state.crashed && state.tick < maxTicks) {
    let thrust = 0;
    try {
      thrust = controller?.(state) ?? 0;
    } catch (e) {
      // Controller errors should not break simulation; treat as no thrust
      thrust = 0;
    }
    const next = step(state, thrust);
    trace.push(next);
    state = next;
  }

  return trace;
}

export function autopilot(state) {
  if (!state || state.landed || state.crashed) return 0;

  // Compute the number of ticks to impact if we apply zero thrust from now
  // altitude_k = altitude - k*v - k*(k+1)
  let k = 1;
  let altAfterK = state.altitude - k * state.velocity - k * (k + 1);
  const maxLook = 10000;
  while (altAfterK > 0 && k < maxLook) {
    k += 1;
    altAfterK = state.altitude - k * state.velocity - k * (k + 1);
  }

  // If we're not going to impact in a reasonable horizon, do nothing
  if (k >= maxLook) return 0;

  // Velocity at the moment of impact if we do nothing until then (before thrust on last tick):
  const vImpact = state.velocity + 2 * k;
  const unitsNeededAtImpact = Math.max(0, Math.ceil((vImpact - 4) / 4));

  if (unitsNeededAtImpact <= state.fuel) {
    // Wait until the final tick to perform the braking burn for fuel efficiency
    if (k === 1) return unitsNeededAtImpact;
    return 0;
  }

  // Not enough fuel to brake at the last moment; fallback to best-effort immediate burn
  const immediateNeeded = Math.max(0, Math.ceil((state.velocity + 2 - 4) / 4));
  return Math.min(state.fuel, immediateNeeded);
}

export function score(initialFuel, fuelUsed, landingVelocity, crashed) {
  if (crashed) return 0;
  const init = Number(initialFuel) || 0;
  const used = Number(fuelUsed) || 0;
  const remaining = Math.max(0, init - used);
  return remaining * 10 + Math.max(0, (4 - landingVelocity) * 25);
}
